{
        Instance storage inst = _getInstance(instanceId);
        ActionEvent storage ev = inst.events[EventKey.StartEvent_D];
        require(ev.exists, "event not set");
        require(ev.state == ElementState.ENABLED, "event state not allowed");

        ev.state = ElementState.COMPLETED;
        emit ActionEventDone(instanceId, EventKey.StartEvent_D);
        inst.messages[MessageKey.SubmitD].state = ElementState.ENABLED;

    }

{
        Instance storage inst = _getInstance(instanceId);
        Message storage m = inst.messages[MessageKey.SubmitD];
        require(m.exists, "message not set");
        _checkParticipant(inst, m.sendParticipant);
        require(m.state == ElementState.ENABLED, "message state not allowed");

        m.fireflyTranId = fireflyTranId;
        m.state = ElementState.COMPLETED;
        emit MessageSent(instanceId, MessageKey.SubmitD, fireflyTranId);
        inst.gateways[GatewayKey.GateD].state = ElementState.ENABLED;

    }

{
        Instance storage inst = _getInstance(instanceId);
        Message storage m = inst.messages[MessageKey.ReturnD];
        require(m.exists, "message not set");
        _checkParticipant(inst, m.sendParticipant);
        require(m.state == ElementState.ENABLED, "message state not allowed");

        m.fireflyTranId = fireflyTranId;
        m.state = ElementState.COMPLETED;
        emit MessageSent(instanceId, MessageKey.ReturnD, fireflyTranId);
        inst.events[EventKey.EndEvent_D].state = ElementState.ENABLED;

    }

{
        Instance storage inst = _getInstance(instanceId);
        Gateway storage g = inst.gateways[GatewayKey.GateD];
        require(g.exists, "gateway not set");
        require(g.state == ElementState.ENABLED, "gateway state not allowed");

        g.state = ElementState.COMPLETED;
        emit GatewayDone(instanceId, GatewayKey.GateD);
        if (inst.stateMemory.DeliverD == true) {
            inst.messages[MessageKey.ReturnD].state = ElementState.ENABLED;
        }
        else {
            inst.events[EventKey.EndEvent_D].state = ElementState.ENABLED;
        }

    }

{
        Instance storage inst = _getInstance(instanceId);
        ActionEvent storage ev = inst.events[EventKey.EndEvent_D];
        require(ev.exists, "event not set");
        require(ev.state == ElementState.ENABLED, "event state not allowed");

        ev.state = ElementState.COMPLETED;
        emit ActionEventDone(instanceId, EventKey.EndEvent_D);

    }
